// License validation logic
// Edit VALID_KEYS to add/remove license keys
// Each entry: { key, allowedUsers }

const VALID_KEYS = [
  { key: 'qocVjUVNzT5c68oxw6hP2lYkD', allowed_users: 5 }
  // Add more keys here
];

// Handle both JSON-parsed body and text/plain body
let licenseKey = '';
const item = items[0].json;

if (item.body && typeof item.body === 'object') {
  licenseKey = item.body.licenseKey || '';
} else if (item.body && typeof item.body === 'string') {
  try {
    const parsed = JSON.parse(item.body);
    licenseKey = parsed.licenseKey || '';
  } catch (e) {}
} else if (item.licenseKey) {
  licenseKey = item.licenseKey;
}

const match = VALID_KEYS.find(k => k.key === licenseKey.trim());

if (match) {
  return [{ json: { valid: true, allowed_users: match.allowed_users } }];
}

return [{ json: { valid: false, allowed_users: 0 } }];
